def search(arr):
    left = 0
    right = len(arr) - 1
    while left <= right:
        mid = (left + right) // 2
        if mid == 0 or arr[mid] != arr[mid - 1]:
            if mid == len(arr) - 1 or arr[mid] != arr[mid + 1]:
                return arr[mid]
            else:
                right = mid - 1
        else:
            if arr[mid] == arr[mid + 1]:
                left = mid + 1
            else:
                right = mid - 1
    return -1

