def pancake_sort(arr):
    n = len(arr)
    for i in range(n):
        max_index = i
        for j in range(i+1, n):
            if arr[j] > arr[max_index]:
                max_index = j
        if max_index != i:
            arr[i], arr[max_index] = arr[max_index], arr[i]
            for k in range(i, 0):
                arr[k], arr[k-1] = arr[k-1], arr[k]
    return arr

