def group_tuples(tuples):
    result = []
    for i in range(len(tuples)):
        if i == 0:
            result.append(tuples[i])
        else:
            if tuples[i][0] == result[-1][0]:
                result[-1].append(tuples[i][1])
            else:
                result.append(tuples[i])
    return result
